  ('promotion-1aab856d-moex-00050', 'promotion-1aab856d', 'promotion-1aab856d-moex-112-3082b5f1', 'sub-promotion-1aab856d-02', NULL, 'single_choice', '關於國家賠償之協議先行程序，下列敘述何者正確？', '["請求國家賠償時，得以言詞向賠償義務機關提出請求", "國家賠償協議成立時，應作成協議書，該項協議書須經公證後，始得為執行名義", "賠償義務機關自開始協議之日起逾60日協議不成立時，請求權人得提起損害賠償之訴", "請求國家賠償時，法院得依聲請為假扣押，命賠償義務機關暫先支付精神慰撫金"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:42+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "130", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "移民行政"}'::jsonb, NULL),
  ('promotion-1aab856d-moex-00051', 'promotion-1aab856d', 'promotion-1aab856d-moex-112-3082b5f1', 'sub-promotion-1aab856d-02', NULL, 'single_choice', '關於行政機關將違法行政處分轉換為與原處分具有相同實質及程序要件之其他處分，下列敘述何 者錯誤？', '["行政處分若違反程序或方式規定，或有顯然錯誤，應屬得補正或更正之範圍，非屬得轉換之瑕疵", "轉換對公益有重大危害或對當事人更不利者，不得轉換", "轉換後之行政處分自始取代違法之原處分，故行政機關不須為轉換之表示", "羈束處分不得轉換為裁量處分"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:42+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "130", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "移民行政"}'::jsonb, NULL),
